import java.util.List;

public class AverageBalanceCalculator {

    public static double calculateAverageBalance(List<Double> closingBalances) {
        // Check if the list is empty
        if (closingBalances.isEmpty()) {
            return 0.0;
        }

        // Initialize the sum of balances
        double totalSum = 0.0;

        // Iterate through the list and sum up the balances
        for (double balance : closingBalances) {
            totalSum += balance;
        }

        // Calculate the average
        double average = totalSum / closingBalances.size();

        // Return the average
        return average;
    }

