import java.util.*;

public class SubstringFinder {
    public int findLargestSubstring(List<String> strings) {
        int maxLength = 0;

        // Iterate through each string
        for (int i = 0; i < strings.size(); i++) {
            String str = strings.get(i);
            int n = str.length();

            // Generate all substrings of the current string
            for (int j = 0; j < n; j++) {
                for (int k = j + 1; k <= n; k++) {
                    String substring = str.substring(j, k);
                    String reversedSubstring = new StringBuilder(substring).reverse().toString();

