import java.util.*;

public class MazeTravel {
    public static String canTravelMaze(int n, int[] start, int[] end, int[][] paths) {
        // Create an adjacency list to represent the graph
        List<List<Integer>> graph = new ArrayList<>();
        for (int i = 0; i < n * n; i++) {
            graph.add(new ArrayList<>());
        }

        // Build the graph from the paths
        for (int[] path : paths) {
            int u = path[0];
            int v = path[1];
            graph.get(u).add(v);
            graph.get(v).add(u);
        }

        // Convert start and end coordinates to 1D index
        int startIndex = start[0] * n + start[1];
        int endIndex = end[0] * n + end[1];

        // Create a visited array
        boolean[] visited = new boolean[n * n];

        // Perform DFS to check if there is a path from start to end
        if (dfs(graph, visited, startIndex, endIndex)) {
            return "can be travelled";
        } else {
            return "cannot be travelled";
        }
    }

    private static boolean dfs(List<List<Integer>> graph, boolean[] visited, int current, int target) {
        // If the current node is the target, return true
        if (current == target) {
            return true;
        }

        // Mark the current node as visited
        visited[current] = true;

        // Recur for all the vertices adjacent to this vertex
        for (int neighbor : graph.get(current)) {
            if (!visited[neighbor]) {
                if (dfs(graph, visited, neighbor, target)) {
                    return true;
                }
            }
        }

        // If no path is found, return false
