        }

        // Step 2: Calculate the sum of the lengths of the two words
        int sumOfLengths = word1.length() + word2.length();

        // Step 3: Compute the approximate value as a fraction
        int numerator = commonCount;
        int denominator = sumOfLengths;

        // Step 4: Reduce the fraction
        int gcd = gcd(numerator, denominator);
        numerator /= gcd;
        denominator /= gcd;

        // Step 5: Format the result
        return String.format("appx(%s, %s) = %d/%d", word1, word2, numerator, denominator);
    }

    // Helper method to calculate the greatest common divisor (GCD)
    private static int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

