```java
public class Solution {
    public int minInsertions(String s) {
        int open = 0; // Counter for unmatched opening parentheses
        int close = 0; // Counter for unmatched closing parentheses

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);

            if (c == '(') {
                open++;
            } else if (c == ')') {
                if (open > 0) {
                    open--;
                } else {
                    close++;
                }
            }
        }

        // Each unmatched opening parenthesis needs a corresponding closing parenthesis
        return open + close;
    }

    public static void main(String[] args) {
        Solution solution = new Solution();

        // Test cases
        System.out.println(solution.minInsertions("(()))")); // Output: 1
        System.out.println(solution.minInsertions("((()))")); // Output: 0
    }
}
