import java.util.HashSet;
import java.util.Set;

public class SquarePermutations {

    public static int squarePermutations(int[] A) {
        Set<Integer> perfectSquares = new HashSet<>();
        for (int i = 1; i <= 1000; i++) {
            perfectSquares.add(i * i);
        }

        return backtrack(A, 0, new boolean[A.length], new int[A.length], perfectSquares);
