public class BoomerangChecker {
    public static boolean isBoomerang(int[][] points) {
        // Extract coordinates
        int x1 = points[0][0];
        int y1 = points[0][1];
        int x2 = points[1][0];
        int y2 = points[1][1];
        int x3 = points[2][0];
        int y3 = points[2][1];

        // Calculate the area using the determinant method
        int area = x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2);

        // If the area is zero, points are collinear
        return area != 0;
    }

